import{_ as t,o as r,c as a,ae as s}from"./chunks/framework.B6gjLfeO.js";const c=JSON.parse('{"title":"Cross-Events Export API","description":"","frontmatter":{"title":"Cross-Events Export API","slug":"introducing-cross-events-exports-api"},"headers":[],"relativePath":"account-hub/introducing-cross-events-exports-api.md","filePath":"account-hub/introducing-cross-events-exports-api.md"}'),o={name:"account-hub/introducing-cross-events-exports-api.md"};function i(n,e,l,d,p,u){return r(),a("div",null,[...e[0]||(e[0]=[s('<p>Branch&#39;s new Cross-Events Export API is a powerful tool for querying and comparing large pools of data across multiple sources.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>With the Cross-Events Export API your queries can access extensive aggregate-level data, return an unlimited number of rows, and include as many dimensions as you want.</p><p>You can also pull from Log Click Warehouse, Log Impression Warehouse, and Aggregate SAN CCI Warehouse <a href="./cross-events-export-api.html#notes-on-data-sources">data</a>.</p><h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Limitation</th><th>Details</th></tr></thead><tbody><tr><td>Max Number of Rows Returned</td><td>No limit. If the result has over 200,000 rows, multiple files will be returned.</td></tr><tr><td>Export Window</td><td>Rolling 2 year window.</td></tr><tr><td>Max Number of Dimensions</td><td>No limit.</td></tr><tr><td>Max Number of Days Queried</td><td>No limit.</td></tr><tr><td>Rate Limits</td><td>2 requests per second. 5 requests per minute. 150 requests per hour.</td></tr><tr><td>Data Readiness</td><td>Data generally takes ~1.5 hours to be ready. To check for data readiness, you can use Branch&#39;s <a href="./custom-exports-api.html#check-data-readiness">Custom Exports API</a> and set the <code>warehouse_meta_type</code> to <code>AGGREGATE</code>.</td></tr></tbody></table><h2 id="try-it" tabindex="-1">Try It! <a class="header-anchor" href="#try-it" aria-label="Permalink to &quot;Try It!&quot;">​</a></h2><p>Try out the Cross-Events Export API in your browser, using your Branch data:</p><p>Request Data Export</p><p><a href="./retrieveexportdownloadstatus.html">Retrieve Export Download Status</a></p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to use the Cross-Events Export API, you first need to:</p><ol><li>Create a Branch Dashboard.</li><li>Enable Ads <strong>and</strong> start running ad campaigns from your Branch account.</li><li>Implement the appropriate Branch SDK into your mobile app (<a href="./ios-sdk-overview.html">iOS</a> | <a href="./android-sdk-overview.html">Android</a>).</li><li>Make sure you have the appropriate permissions set on your user account. See the <a href="./cross-events-export-api.html#access">Access</a> section in our reference guide for more.</li></ol><h2 id="use-case-examples" tabindex="-1">Use Case Examples <a class="header-anchor" href="#use-case-examples" aria-label="Permalink to &quot;Use Case Examples&quot;">​</a></h2><p>View the example queries below to see what&#39;s possible with the Cross-Events Export API:</p><p><a href="./cross-events-export-api.html#query-all-standard-events">Query All Standard Branch Events</a></p><p><a href="./cross-events-export-api.html#split-revenue-field-by-ad-partner">Split Revenue Field by Ad Partner</a></p><p><a href="./cross-events-export-api.html#split-various-events-by-ad-partner">Split a Sampling of Events by Ad Partner</a></p><p><a href="./cross-events-export-api.html#pull-all-links-for-an-app">Pull All Links for an App</a></p><p><a href="./cross-events-export-api.html#add-a-filter">Add a Filter</a></p><h2 id="learn-more" tabindex="-1">Learn More <a class="header-anchor" href="#learn-more" aria-label="Permalink to &quot;Learn More&quot;">​</a></h2><p>For all the details about the Cross-Events Export API, visit our reference <a href="https://docs.app.link/e/qAO5SWdzjIb" target="_blank" rel="noreferrer">guide</a>.</p>',22)])])}const m=t(o,[["render",i]]);export{c as __pageData,m as default};
